package main

import (
	"bytes"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

const maxBodySize = 1024 * 1024 // 1MB limit to prevent resource exhaustion

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Validate URL components
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must contain a valid host"})
	}

	// Prevent SSRF by blocking private IP ranges
	if err := checkForPrivateIP(parsedURL.Hostname()); err != nil {
		return ctx.JSON(http.StatusForbidden, map[string]string{"error": err.Error()})
	}

	// Create HTTP client with security settings
	client := &http.Client{
		Timeout: 3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 10 { // Limit redirects to prevent infinite loops
				return fmt.Errorf("too many redirects")
			}
			return nil
		},
	}

	// Create request with context propagation (cancels if client disconnects)
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set appropriate headers
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Handle non-success status codes appropriately
	if resp.StatusCode != http.StatusOK {
		var errMsg string
		var statusCode int

		switch resp.StatusCode {
		case http.StatusNotFound:
			errMsg = "Target URL not found"
			statusCode = http.StatusNotFound
		case http.StatusForbidden:
			errMsg = "Access to target URL is forbidden"
			statusCode = http.StatusForbidden
		default:
			errMsg = fmt.Sprintf("Server returned status code %d", resp.StatusCode)
			statusCode = http.StatusBadGateway
		}
		return ctx.JSON(statusCode, map[string]string{"error": errMsg})
	}

	// Validate content type is HTML-like
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(strings.ToLower(contentType), "text/html") && !strings.Contains(strings.ToLower(contentType), "application/xhtml+xml") {
		return ctx.JSON(http.StatusOK, PreviewResponse{})
	}

	// Read limited body to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodySize))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// checkForPrivateIP resolves the host to IPs and blocks access to private ranges
func checkForPrivateIP(host string) error {
	ips, err := net.LookupHost(host)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %v", err)
	}

	for _, ipStr := range ips {
		ip := net.ParseIP(ipStr)
		if ip == nil {
			continue
		}

		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// isPrivateIP checks if an IP address falls into any private network range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10: // 10.0.0.0/8
			return true
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31: //172.16.0.0/12
			return true
		case ip4[0] == 192 && ip4[1] == 168: //192.168.0.0/16
			return true
		case ip4[0] == 169 && ip4[1] == 254: //169.254.0.0/16 (link-local)
			return true
		default:
			return false
		}
	}

	// Check IPv6 private ranges (Go 1.17+)
	if ip.IsPrivate() { // fc00::/7 unique local addresses
		return true
	}

	return false
}

// extractTitleAndDescription parses HTML to get title and meta description safely
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop early if both values are found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

