	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

// URLRequest represents the request body structure for URL preview
type URLRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the response structure with preview data
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// extractTitle parses HTML to find the page title
func extractTitle(doc *html.Node) string {
	var title string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = n.FirstChild.Data
			}
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title
}

// extractDescription parses HTML to find the meta description
func extractDescription(doc *html.Node) string {
	var description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				switch attr.Key {
				case "name":
					nameAttr = attr.Val
				case "content":
					contentAttr = attr.Val
				}
			}
			if nameAttr == "description" && contentAttr != "" {
				description = contentAttr
				return // Return first occurrence of description meta tag
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return description
}

// FetchURLPreview handles POST requests to generate URL previews
func FetchURLPreview(ctx echo.Context) error {
	// Bind request body to struct
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("Invalid request body: %v", err)})
	}

	// Validate URL presence
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("Invalid URL format: %v", err)})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must use http or https scheme"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with custom User-Agent to avoid blocking
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Failed to create request: %v", err)})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/129.0.0.0 Safari/537.36")

	// Fetch the URL content
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Received non-success status code: %d", resp.StatusCode)})
	}

	// Parse HTML document
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Failed to parse HTML: %v", err)})
	}

	// Extract preview data
	title := extractTitle(doc)
	description := extractDescription(doc)

	// Return successful response
	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Add middleware for logging and panic recovery
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register preview handler
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	if err := e.Start(":8080"); err != nil && err != http.ErrServerClosed {
		e.Logger.Fatal("Server shutdown error:", err)
	}
}

