					}
				}
				if nameAttr == "description" && contentAttr != "" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

