type RequestBody struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to /preview to extract URL preview data
func FetchURLPreview(ctx echo.Context) error {
	// Bind incoming request body to struct
	var req RequestBody
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body: " + err.Error(),
		})
	}

	// Validate URL is provided
	if strings.TrimSpace(req.URL) == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL parameter is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the target URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "URL returned non-success status: " + resp.Status,
		})
	}

	// Parse HTML content from response
	rootNode, err := htmlparse.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content: " + err.Error(),
		})
	}

	// Extract preview data
	title := extractTitle(rootNode)
	description := extractMetaDescription(rootNode)

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle retrieves the text content of the HTML <title> tag
func extractTitle(root *htmlparse.Node) string {
	var title string
	var traverse func(*htmlparse.Node)

	traverse = func(n *htmlparse.Node) {
		if n.Type == htmlparse.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == htmlparse.TextNode {
				title = strings.TrimSpace(html.UnescapeString(n.FirstChild.Data))
			}
			return // Stop after finding first title element
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(root)
	return title
}

// extractMetaDescription retrieves content from meta tags (name="description" or property="og:description")
func extractMetaDescription(root *htmlparse.Node) string {
	var description string
	var traverse func(*htmlparse.Node)

	traverse = func(n *htmlparse.Node) {
		if n.Type == htmlparse.ElementNode && n.Data == "meta" {
			// Check for standard description meta tag
			if getAttribute(n, "name") == "description" && description == "" {
				description = strings.TrimSpace(html.UnescapeString(getAttribute(n, "content")))
			}

			// Fallback to Open Graph description if standard not found
			if getAttribute(n, "property") == "og:description" && description == "" {
				description = strings.TrimSpace(html.UnescapeString(getAttribute(n, "content")))
			}

			// Stop traversal once we find a valid description
			if description != "" {
				return
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(root)
	return description
}

// getAttribute retrieves the value of a specific HTML attribute from a node
func getAttribute(n *htmlparse.Node, key string) string {
	for _, attr := range n.Attr {
		if attr.Key == key {
			return attr.Val
		}
	}
	return ""
}

func main() {
	// Initialize Echo framework instance
	e := echo.New()

	// Add middleware for logging and panic recovery
	e.Use(middleware.Logger())
	e.Use(middleware.Recovery())

	// Register URL preview handler
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

