		case ip4[0] == 192 && ip4[1] == 168: //192.168.0.0/16
			return true
		case ip4[0] == 169 && ip4[1] == 254: //169.254.0.0/16 (link-local)
			return true
		case ip4[0] == 100 && (ip4[1] >= 64 && ip4[1] <= 127): //100.64.0.0/10 (CGNAT)
