					case "content":
						metaContent = strings.TrimSpace(attr.Val)
					}
				}
				if metaName == "description" && metaContent != "" {
					description = metaContent
				}
			}
		}

		// Continue traversing children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
