// FetchURLPreview handles POST requests to extract URL preview data
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	// Validate and parse the input URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Ensure we only allow HTTP/HTTPS schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are supported"})
	}

	// Create HTTP client with timeout
	client := &http.Client{Timeout: 3 * time.Second}

	// Prepare GET request with custom user agent
	reqHTTP, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	reqHTTP.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute request
	resp, err := client.Do(reqHTTP)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch target URL"})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Target URL returned status code: %d", resp.StatusCode)})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response content"})
	}

	// Extract preview data from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML content to extract title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	// Recursive traversal function to search HTML nodes
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract title from <title> tag
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
		}

		// Extract description from <meta name="description"> tag
		if n.Type == html.ElementNode && n.Data == "meta" {
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				switch attr.Key {
				case "name":
					nameAttr = strings.ToLower(attr.Val)
				case "content":
					contentAttr = strings.TrimSpace(attr.Val)
				}
			}
			if nameAttr == "description" && contentAttr != "" {
				description = contentAttr
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

// Main function to initialize Echo server and register handlers
func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

