// checkForPrivateIP resolves the host to IP addresses and checks if any are in private/loopback ranges
func checkForPrivateIP(host string) error {
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %v", err)
	}

