// isPrivateIP checks if an IP address is in a private or reserved range
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Check loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Check link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
