		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content: " + err.Error(),
		})
	}

	// Extract title and description from parsed HTML
	title := extractTitle(doc)
	description := extractDescription(doc)

	// Return the preview data as JSON
	return ctx.JSON(http.StatusOK, URLPreview{
		Title:       title,
		Description: description,
	})
}

// extractTitle traverses the HTML DOM to find and return the page title
func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		var title strings.Builder
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			if c.Type == html.TextNode {
				title.WriteString(c.Data)
			}
		}
		return strings.TrimSpace(title.String())
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if t := extractTitle(c); t != "" {
			return t
		}
	}
	return ""
}

// extractDescription traverses the HTML DOM to find and return the meta description
func extractDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var nameAttr, contentAttr string
		for _, attr := range n.Attr {
			switch attr.Key {
			case "name":
				nameAttr = attr.Val
			case "content":
				contentAttr = attr.Val
			}
		}

		if strings.EqualFold(nameAttr, "description") {
			return strings.TrimSpace(contentAttr)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if d := extractDescription(c); d != "" {
			return d
		}
	}
	return ""
}

func main() {
	// Initialize Echo framework instance
	e := echo.New()

	// Register the preview handler under /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the HTTP server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

