	if err := checkForPrivateIP(parsedURL.Host); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	// Fetch URL with context propagation and timeout
	client := &http.Client{Timeout: 3 * time.Second}
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set appropriate headers
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if error is due to client cancellation
		if ctx.Request().Context().Err() != nil {
			return ctx.NoContent(http.StatusRequestTimeout)
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Handle non-success status codes
	if resp.StatusCode >= 400 {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("Remote server returned: %s", resp.Status)})
	}

	// Read limited body size to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodySize))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// checkForPrivateIP resolves the host to IPs and blocks access to private/loopback addresses
func checkForPrivateIP(host string) error {
	// Remove port if present
	hostWithoutPort, _, err := net.SplitHostPort(host)
	if err != nil {
		// If no port, use original host
		hostWithoutPort = host
	}

	ips, err := net.LookupIP(hostWithoutPort)
	if err != nil {
		return fmt.Errorf("could not resolve host: %w", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is blocked")
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is in a private or loopback range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check private subnet ranges
	privateCIDRs := []string{
		"10.0.0.0/8",     // RFC1918 private A class
		"172.16.0.0/12",  // RFC1918 private B class
		"192.168.0.0/16", // RFC1918 private C class
		"100.64.0.0/10",  // Carrier-grade NAT
		"198.18.0.0/15",  // Benchmarking networks
		"fc00::/7",       // IPv6 Unique Local Addresses
		"fe80::/10",      // IPv6 link-local addresses
	}

	for _, cidr := range privateCIDRs {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}

	return false
}

// extractTitleAndDescription parses HTML to extract title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop traversing once we have both values
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						if strings.ToLower(attr.Val) == "description" {
							nameAttr = attr.Val
						}
					case "content":
						contentAttr = attr.Val
					}
				}
				if nameAttr != "" && contentAttr != "" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

