			if req.URL.Scheme != "http" && req.URL.Scheme != "https" {
				return fmt.Errorf("redirect to unsupported scheme: %s", req.URL.Scheme)
			}
			return nil
		},
	}

	// Create proper GET request with valid user agent
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the target URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL content"})
	}
	defer resp.Body.Close()

	// Validate response status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("URL returned status code: %d", resp.StatusCode)})
	}

	// Validate content type is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusUnsupportedMediaType, map[string]string{"error": "URL does not return HTML content"})
	}

	// Read limited response body to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024)) // 1MB limit
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response content"})
	}

	// Extract and sanitize metadata
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML content to find title and meta description, then sanitizes them
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	sanitizer := bluemonday.StrictPolicy()
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string
	foundTitle := false
	foundDescription := false

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop processing if we have both values or reach the body tag
		if (foundTitle && foundDescription) || (n.Type == html.ElementNode && n.Data == "body") {
			return
		}

		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				// Extract text from title tag
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						title = sanitizer.Sanitize(strings.TrimSpace(c.Data))
						foundTitle = true
						break
					}
				}
			case "meta":
				// Extract description from meta tags (standard and OpenGraph)
				var metaName, metaContent string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name", "property":
						metaName = strings.ToLower(attr.Val)
					case "content":
						metaContent = attr.Val
					}
				}

				if (metaName == "description" || metaName == "og:description") && metaContent != "" {
					description = sanitizer.Sanitize(strings.TrimSpace(metaContent))
					foundDescription = true
				}
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

