// FetchURLPreview handles POST requests to extract title and meta description from a given URL
func FetchURLPreview(ctx echo.Context) error {
	// Bind incoming JSON request to RequestBody struct
	req := new(RequestBody)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
