	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: fmt.Sprintf("Failed to parse HTML content: %v", err),
		})
	}

	// Extract page title
	title := ""
	var extractTitle func(*html.Node)
	extractTitle = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractTitle(c)
		}
	}
	extractTitle(doc)

	// Extract meta description
	description := ""
	var extractDescription func(*html.Node)
	extractDescription = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var metaName, metaContent string
			for _, attr := range n.Attr {
				switch strings.ToLower(attr.Key) {
				case "name":
					metaName = strings.ToLower(attr.Val)
				case "content":
					metaContent = attr.Val
				}
			}
			if metaName == "description" && metaContent != "" {
				description = strings.TrimSpace(metaContent)
				return
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractDescription(c)
		}
	}
	extractDescription(doc)

	// Return successful preview response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
