	Title       string `json:"title"`
	Description string `json:"description"`
}

// CustomValidator implements Echo's validator interface
type CustomValidator struct {
	validator *validator.Validate
}

func (cv *CustomValidator) Validate(i interface{}) error {
	if err := cv.validator.Struct(i); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, err.Error())
	}
	return nil
}

// FetchURLPreview handles the URL preview request
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest

	// Bind and validate the request body
	if err := ctx.Bind(&req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid request body: "+err.Error())
	}
	if err := ctx.Validate(&req); err != nil {
		return err
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the target URL
	resp, err := client.Get(req.URL)
	if err != nil {
		// Handle timeout errors specifically
		var netErr net.Error
		if errors.As(err, &netErr) && netErr.Timeout() {
			return echo.NewHTTPError(http.StatusRequestTimeout, "Request to target URL timed out")
		}
		return echo.NewHTTPError(http.StatusInternalServerError, "Failed to fetch target URL: "+err.Error())
	}
	defer resp.Body.Close()

	// Check for non-OK HTTP status codes
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusBadRequest {
		return echo.NewHTTPError(http.StatusBadGateway, "Target URL returned non-OK status: "+resp.Status)
	}

	// Parse HTML content using goquery
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "Failed to parse HTML content: "+err.Error())
	}

	// Extract page title
	title := doc.Find("title").Text()

	// Extract meta description (fallback to Open Graph description if available)
	description := doc.Find("meta[name='description']").AttrOr("content", "")
	if description == "" {
		description = doc.Find("meta[property='og:description']").AttrOr("content", "")
	}

	// Prepare and return the response
	preview := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, preview)
}

func main() {
	// Initialize Echo instance
