package main

import (
	"bytes"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body structure for URL preview request
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body structure for URL preview result
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

// FetchURLPreview handles POST requests to extract title and meta description from a given URL
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	// Validate and parse the input URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Ensure URL uses HTTP/HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Configure HTTP client with timeout and custom user agent
	client := &http.Client{Timeout: 3 * time.Second}
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the target URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Check for successful HTTP response
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("URL returned status code: %d", resp.StatusCode)})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract title and description from HTML content
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML content to find title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	// Traverse HTML node tree to find target elements
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				// Collect all text content inside title tag
				var titleBuilder strings.Builder
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						titleBuilder.WriteString(c.Data)
					}
				}
				title = strings.TrimSpace(titleBuilder.String())
			case "meta":
				// Check for meta description tag
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = strings.TrimSpace(attr.Val)
					}
				}
				if nameAttr == "description" && contentAttr != "" {
					description = contentAttr
				}
			}
		}

		// Continue traversing child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Initialize Echo framework
	e := echo.New()
	// Register handler for preview endpoint
	e.POST("/preview", FetchURLPreview)

	fmt.Println("Server starting on :8080...")
	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

