// isPrivateIP checks if an IP address is in a private or reserved range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check IPv4 private ranges
	if ipv4 := ip.To4(); ipv4 != nil {
		switch {
		case ipv4[0] == 10:
			return true
		case ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31:
			return true
		case ipv4[0] == 192 && ipv4[1] == 168:
			return true
		case ipv4[0] == 127:
			return true
		}
		return false
	}

	// Check IPv6 private ranges
	if ipv6 := ip.To16(); ipv6 != nil {
		// Unique Local Address (ULA) fc00::/7
		if ipv6[0]&0xfe == 0xfc {
			return true
		}
		// Reserved for documentation, testing, etc.
		if ipv6[0] == 0x20 && ipv6[1] == 0x01 && ipv6[2] == 0x0d && ipv6[3] == 0xb8 {
			return true
		}
	}

	return false
}

// extractTitleAndDescription parses HTML to extract title and meta description (including Open Graph)
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop early if we've found both fields
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				extractMetaTags(n, &description)
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

// extractMetaTags handles meta tag parsing for description fields
func extractMetaTags(n *html.Node, description *string) {
	if *description != "" {
		return // Skip if we already have a description
	}

	var metaName, metaProperty, metaContent string
	for _, attr := range n.Attr {
		key := strings.ToLower(attr.Key)
		switch key {
		case "name":
			metaName = strings.ToLower(attr.Val)
		case "property":
			metaProperty = strings.ToLower(attr.Val)
		case "content":
			metaContent = attr.Val
		}
	}

	// Check for standard description meta tag
	if metaName == "description" && metaContent != "" {
		*description = strings.TrimSpace(metaContent)
		return
	}

	// Check for Open Graph description
	if metaProperty == "og:description" && metaContent != "" {
		*description = strings.TrimSpace(metaContent)
	}
}

