// URLRequest represents the incoming request body structure
type URLRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	// Initialize Echo server
	e := echo.New()

	// Register the preview handler
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	if err := e.Start(":8080"); err != http.ErrServerClosed {
		e.Logger.Fatalf("Failed to start server: %v", err)
	}
}

// FetchURLPreview handles POST requests to extract URL preview data
func FetchURLPreview(ctx echo.Context) error {
	// Parse incoming request body
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body format"})
	}

	// Validate URL presence
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL parameter is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the target URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("URL returned non-success status: %s", resp.Status)})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Failed to parse HTML content: %v", err)})
	}

	// Extract preview data
	title := extractTitle(doc)
	description := extractDescription(doc)

	// Return preview response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle retrieves the text content of the HTML title tag
func extractTitle(n *html.Node) string {
	var title string
	var traverse func(*html.Node)

	traverse = func(node *html.Node) {
		if node.Type == html.ElementNode && node.Data == "title" {
			if node.FirstChild != nil && node.FirstChild.Type == html.TextNode {
				title = node.FirstChild.Data
			}
			return
		}

		for child := node.FirstChild; child != nil; child = child.NextSibling {
			traverse(child)
		}
	}

	traverse(n)
	return strings.TrimSpace(title)
}

// extractDescription retrieves the content of the meta description tag
func extractDescription(n *html.Node) string {
	var description string
	var traverse func(*html.Node)

	traverse = func(node *html.Node) {
		if node.Type == html.ElementNode && node.Data == "meta" {
