func FetchURLPreview(ctx echo.Context) error {
	// Parse incoming JSON request
	req := new(urlRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, echo.Map{
			"error": fmt.Sprintf("invalid request body: %v", err),
		})
	}

	// Validate required URL field
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, echo.Map{
			"error": "url field is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, echo.Map{
			"error": fmt.Sprintf("invalid URL format: %v", err),
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, echo.Map{
			"error": "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, echo.Map{
			"error": fmt.Sprintf("failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.JSON(http.StatusServiceUnavailable, echo.Map{
			"error": fmt.Sprintf("remote server returned status: %d", resp.StatusCode),
		})
	}

	// Parse HTML document
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, echo.Map{
			"error": fmt.Sprintf("failed to parse HTML: %v", err),
		})
	}

	// Extract title and description from HTML
	preview := urlPreview{}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract title element content
		if n.Type == html.ElementNode && n.DataAtom == atom.Title {
			var titleBuilder strings.Builder
			var collectTitleText func(*html.Node)
			collectTitleText = func(node *html.Node) {
