	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

func main() {
	e := echo.New()

	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":8080"))
}

func FetchURLPreview(ctx echo.Context) error {
	// Define request structure
	type URLRequest struct {
		URL string `json:"url"`
	}
	var req URLRequest

	// Bind and validate incoming request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body: " + err.Error(),
		})
	}

	// Validate URL scheme is HTTP/HTTPS
	parsedURL, err := url.Parse(req.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid URL: must be a valid HTTP or HTTPS URL",
		})
	}

	// Set up HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the target URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": fmt.Sprintf("URL returned non-200 status code: %d", resp.StatusCode),
		})
	}

	// Parse HTML content
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content: " + err.Error(),
		})
	}

	// Extract page title
	title := doc.Find("title").Text()

	// Extract meta description
	var description string
	doc.Find("meta").Each(func(i int, s *goquery.Selection) {
		nameAttr, exists := s.Attr("name")
		if exists && strings.EqualFold(nameAttr, "description") {
			description, _ = s.Attr("content")
			return // Break after finding first description meta tag
		}
	})

	// Define response structure
	type PreviewResponse struct {
		Title       string `json:"title"`
		Description string `json:"description"`
	}

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

