package main

import (
	"bytes"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body structure for URL preview request
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body structure for URL preview result
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func main() {
	// Initialize Echo framework
	e := echo.New()

	// Register the preview handler under POST /preview
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	// Parse request body
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	// Validate and parse URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Validate URL components
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must contain a valid host"})
	}

	// Configure HTTP client with timeout
	client := &http.Client{Timeout: 5 * time.Second}

	// Create request with context (respects client cancellation)
	reqHTTP, err := http.NewRequestWithContext(
		ctx.Request().Context(),
		http.MethodGet,
		parsedURL.String(),
		nil,
	)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set appropriate headers to mimic a browser
	reqHTTP.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	reqHTTP.Header.Set("Accept-Encoding", "gzip, deflate")
	reqHTTP.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Execute request
	resp, err := client.Do(reqHTTP)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	// Check for successful response
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("URL returned status code: %d", resp.StatusCode)})
	}

	// Verify content type is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusOK, PreviewResponse{})
	}

	// Read up to 1MB of response body (prevents OOM from large files)
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response content"})
	}

	// Extract title and description from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var titleBuilder strings.Builder
	var description string
	var inTitle bool

	tokenizer := html.NewTokenizer(bytes.NewReader(htmlContent))

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// End of document or parsing error, return collected values
			return strings.TrimSpace(titleBuilder.String()), strings.TrimSpace(description)

		case html.StartTagToken:
			token := tokenizer.Token()
			tagName := strings.ToLower(token.Data)

			if tagName == "title" {
				inTitle = true
			} else if tagName == "meta" {
				extractMetaDescription(token, &description)
			}

		case html.SelfClosingTagToken:
			token := tokenizer.Token()
			if strings.ToLower(token.Data) == "meta" {
				extractMetaDescription(token, &description)
			}

		case html.TextToken:
			if inTitle {
				titleBuilder.WriteString(tokenizer.Token().Data)
			}

		case html.EndTagToken:
			token := tokenizer.Token()
			if strings.ToLower(token.Data) == "title" {
				inTitle = false
			}
		}
	}
}

// Helper function to extract meta description from meta tag token
func extractMetaDescription(token html.Token, description *string) {
	if *description != "" {
		return // Already found a description, skip
	}

	var nameAttr, contentAttr string
	for _, attr := range token.Attr {
		attrKey := strings.ToLower(attr.Key)
		switch attrKey {
		case "name":
			nameAttr = strings.ToLower(attr.Val)
		case "content":
			contentAttr = attr.Val
		}
	}

	if nameAttr == "description" && contentAttr != "" {
		*description = contentAttr
	}
}

