// extractTitleAndDescription parses HTML content to find title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					switch key {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" && contentAttr != "" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}

		// Early exit if both fields are found
		if title != "" && description != "" {
			return
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Sanitize output to remove HTML tags and extra whitespace
	title = sanitizeString(title)
	description = sanitizeString(description)

	return title, description
}

// sanitizeString removes HTML tags and trims whitespace from input string
func sanitizeString(s string) string {
	var buf strings.Builder
	inTag := false

	for _, r := range s {
		switch r {
		case '<':
			inTag = true
		case '>':
			inTag = false
		default:
			if !inTag {
				buf.WriteRune(r)
			}
		}
	}

	return strings.TrimSpace(buf.String())
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

