		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "URL is required"})
	}

	// Validate URL has scheme and host
	u, err := url.Parse(req.URL)
	if err != nil || u.Scheme == "" || u.Host == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "Invalid URL: must include a valid scheme (http/https) and host"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: fmt.Sprintf("URL returned status code: %d", resp.StatusCode)})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: fmt.Sprintf("Failed to parse HTML: %v", err)})
	}

	// Extract title tag content
	var title string
	var traverseTitle func(*html.Node)
	traverseTitle = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = n.FirstChild.Data
			}
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
