package main

import (
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// URLRequest represents the POST request body structure
type URLRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the successful response structure
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to extract URL preview data
func FetchURLPreview(c echo.Context) error {
	// Bind request body to URLRequest struct
	req := new(URLRequest)
	if err := c.Bind(req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, fmt.Sprintf("Invalid request body: %v", err))
	}

	// Validate URL presence
	if req.URL == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "URL is required")
	}

	// Validate URL scheme
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		return echo.NewHTTPError(http.StatusBadRequest, "URL must include http:// or https:// scheme")
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the target URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, fmt.Sprintf("Failed to fetch URL: %v", err))
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode != http.StatusOK {
		return echo.NewHTTPError(http.StatusInternalServerError, fmt.Sprintf("Received non-OK status code: %d %s", resp.StatusCode, resp.Status))
	}

	// Parse HTML to extract title and description
	title, description, err := parseHTMLContent(resp.Body)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, fmt.Sprintf("Failed to parse HTML: %v", err))
	}

	// Return successful preview response
	return c.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTMLContent extracts title and meta description from HTML content
func parseHTMLContent(r io.Reader) (string, string, error) {
	tokenizer := html.NewTokenizer(r)
	var title string
	var description string
	inTitle := false

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			err := tokenizer.Err()
			if err == io.EOF {
				// End of document, return collected data
				return title, description, nil
			}
			return "", "", err

		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()

			switch token.Data {
			case "title":
				if tokenType == html.StartTagToken {
					inTitle = true
				}

			case "meta":
				// Extract meta description
				var nameAttr, contentAttr string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						nameAttr = attr.Val
					case "content":
						contentAttr = attr.Val
					}
				}
				if strings.EqualFold(nameAttr, "description") {
					description = contentAttr
				}
			}

		case html.TextToken:
			if inTitle {
				title += tokenizer.Token().Data
			}

		case html.EndTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				inTitle = false
			}
		}
	}
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register preview handler
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

